import React from 'react';
import VideoCard from './VideoCard';

function VideoCardContainer({ videos }) {
    const columnWidth = Math.floor(12 / videos.length);

    return (
        <div className="video-card-container container-fluid">
            <div className="row">
                {videos.map((video, index) => (
                    <div key={index} className={`col-md-${columnWidth} mb-3`}>
                        <VideoCard
                            url={video.url}
                            title={video.title}
                            description={video.description}
                            buttonComponent={video.buttonComponent}
                        />
                    </div>
                ))}
            </div>
        </div>
    );
}

export default VideoCardContainer;
